class BackendGrpcForwarder:
    def __init__(
        self,
        backend_target: str,
        timeout_s: float = 10.0,
        use_tls: bool = False,
        tls_root_certs_path: Optional[str] = None,
    ):
        self.backend_target = backend_target
        self.timeout_s = timeout_s
        self.use_tls = use_tls
        self.tls_root_certs_path = tls_root_certs_path
        self._channel = self._create_channel()

    def _create_channel(self) -> grpc.Channel:
        if self.use_tls:
            root_certs = None
            if self.tls_root_certs_path:
                with open(self.tls_root_certs_path, "rb") as f:
                    root_certs = f.read()
            creds = grpc.ssl_channel_credentials(root_certificates=root_certs)
            return grpc.secure_channel(self.backend_target, creds)
        return grpc.insecure_channel(self.backend_target)

    async def forward_unary_unary(
        self,
        full_method: str,
        body: bytes,
        metadata: Metadata,
    ) -> Tuple[bytes, List[Tuple[str, str]], grpc.StatusCode, str]:
        stub = grpc.aio.GenericStub(self._channel)
        call = stub.unary_unary(
            full_method,
            request_serializer=lambda x: x,
            response_deserializer=lambda x: x,
        )

        try:
            resp = await call(body, timeout=self.timeout_s, metadata=metadata)
            tmd = await call.trailing_metadata()
            status = call.code() or grpc.StatusCode.OK
            details = call.details() or ""
            trailing_list = [(str(k), _safe_str(v)) for k, v in (tmd or ())]
            return resp, trailing_list, status, details
        except grpc.aio.AioRpcError as e:
            tmd = e.trailing_metadata()
            trailing_list = [(str(k), _safe_str(v)) for k, v in (tmd or ())]
            return b"", trailing_list, e.code(), e.details() or ""


def create_app() -> FastAPI:
    backend_target = os.getenv("BACKEND_GRPC_TARGET", "127.0.0.1:50051")
    timeout_s = float(os.getenv("BACKEND_GRPC_TIMEOUT_S", "10.0"))
    use_tls = os.getenv("BACKEND_GRPC_USE_TLS", "0") == "1"
    tls_roots = os.getenv("BACKEND_GRPC_TLS_ROOT_CERTS", "") or None

    allowlist_env = os.getenv("FORWARD_HEADER_ALLOWLIST", "").strip()
    denylist_env = os.getenv("FORWARD_HEADER_DENYLIST", "").strip()
    prefixes_env = os.getenv("FORWARD_HEADER_PREFIXES", "x-").strip()

    allowlist = [h.strip() for h in allowlist_env.split(",") if h.strip()] if allowlist_env else None
    denylist = [h.strip() for h in denylist_env.split(",") if h.strip()] if denylist_env else ["cookie"]
    prefixes = [p.strip() for p in prefixes_env.split(",") if p.strip()] if prefixes_env else None

    forwarder = BackendGrpcForwarder(
        backend_target=backend_target,
        timeout_s=timeout_s,
        use_tls=use_tls,
        tls_root_certs_path=tls_roots,
    )

    app = FastAPI()

    @app.api_route("/grpc/{service}/{method}", methods=["POST"])
    async def grpc_proxy(service: str, method: str, request: Request):
        full_method = f"/{service}/{method}"
        body = await request.body()

        forwarded = _extract_forward_headers(
            request,
            allowlist=allowlist,
            denylist=denylist,
            prefix_filters=prefixes,
        )

        user_md: Dict[str, str] = {}
        for k, v in request.query_params.items():
            if k.startswith("md."):
                user_md[k[3:]] = v

        metadata = _headers_to_grpc_metadata(
            forwarded,
            add=user_md,
        )

        resp_bytes, trailing_md, status, details = await forwarder.forward_unary_unary(
            full_method=full_method,
            body=body,
            metadata=metadata,
        )

        http_headers: Dict[str, str] = {}
        for k, v in trailing_md:
            if k.lower().startswith("x-"):
                http_headers[k] = v

        if status != grpc.StatusCode.OK:
            raise HTTPException(status_code=502, detail={"grpc_status": status.name, "grpc_details": details, "trailing": trailing_md})

        return Response(content=resp_bytes, media_type="application/octet-stream", headers=http_headers)

    @app.get("/healthz")
    async def healthz():
        return JSONResponse({"ok": True})

    return app


def serve_grpc_gateway():
    listen_addr = os.getenv("GATEWAY_GRPC_LISTEN", "0.0.0.0:50052")
    backend_target = os.getenv("BACKEND_GRPC_TARGET", "127.0.0.1:50051")
    timeout_s = float(os.getenv("BACKEND_GRPC_TIMEOUT_S", "10.0"))
    use_tls = os.getenv("BACKEND_GRPC_USE_TLS", "0") == "1"
    tls_roots = os.getenv("BACKEND_GRPC_TLS_ROOT_CERTS", "") or None

    server = grpc.server(futures.ThreadPoolExecutor(max_workers=int(os.getenv("GATEWAY_GRPC_WORKERS", "32"))))
    handler = GatewayService(
        backend_target=backend_target,
        backend_call_timeout_s=timeout_s,
        backend_use_tls=use_tls,
        backend_tls_root_certs_path=tls_roots,
    )
    server.add_generic_rpc_handlers((handler,))
    server.add_insecure_port(listen_addr)
    server.start()
    server.wait_for_termination()


def serve_http_gateway():
    host = os.getenv("GATEWAY_HTTP_HOST", "0.0.0.0")
    port = int(os.getenv("GATEWAY_HTTP_PORT", "8080"))
    app = create_app()
    uvicorn.run(app, host=host, port=port)


if __name__ == "__main__":
    mode = os.getenv("GATEWAY_MODE", "http").lower().strip()
    if mode == "grpc":
        serve_grpc_gateway()
    else:
        serve_http_gateway()